const items = $input.all();
const results = [];

for (const item of items) {
  const emailData = {
    from: item.json.from || '',
    to: item.json.to || '',
    subject: item.json.subject || '',
    date: item.json.date || '',
    messageId: item.json.headers ? item.json.headers['message-id'] : '',
    text: item.json.text || item.json.textAsHtml || item.json.html || '',
    hasAttachment: false,
    uid: item.json.attributes ? item.json.attributes.uid : null
  };
  if (item.binary && Object.keys(item.binary).length > 0) {
    emailData.hasAttachment = true;
  }
  results.push({ json: emailData, binary: item.binary || {} });
}

return results;

