const invoiceItems = $('Parse Output').all();
const binaryItems = $('Split Attachments').all();
const results = [];

for (let i = 0; i < invoiceItems.length; i++) {
  const invoiceItem = invoiceItems[i];
  const binaryItem = binaryItems[i] || { binary: {} };

  let fromEmail = '';
  const email = invoiceItem.json.email || {};
  if (typeof email.from === 'string') fromEmail = email.from;
  else if (email.from?.text) fromEmail = email.from.text;
  else if (email.from?.value?.[0]?.address) fromEmail = email.from.value[0].address;

  const invoice = invoiceItem.json.invoice;

  results.push({
    json: {
      invoice,
      email: {
        subject: email.subject || '',
        from: fromEmail,
        date: email.date || ''
      },
      isStorno: invoice.is_storno || false
    },
    binary: binaryItem.binary || {}
  });
}

return results;

