const invoiceItems = $('Parse Output').all();
const binaryItems = $('Split Attachments').all();
const results = [];

for (let i = 0; i < invoiceItems.length; i++) {
  const invoiceData = invoiceItems[i];
  const binaryData = binaryItems[i];
  if (!binaryData?.binary) continue;

  const binaryKey = Object.keys(binaryData.binary)[0] || 'data';
  const pdfBinary = binaryData.binary[binaryKey];
  if (!pdfBinary) continue;

  const fileName = pdfBinary.fileName ||
    `${invoiceData.json.invoice?.invoice_number || 'invoice'}.pdf`;

  results.push({
    json: {
      invoice: invoiceData.json.invoice,
      email: invoiceData.json.email,
      fileName
    },
    binary: { data: pdfBinary }
  });
}

return results;

