// Dateiname: YYMMDD_LIEFERANT_RECHNUNGSNR.pdf
const items = $input.all();
const results = [];

for (const item of items) {
  const invoice = item.json.invoice || {};
  const binaryData = item.binary?.data;
  if (!binaryData) continue;

  // Datum
  let shortDate = '';
  if (invoice.invoice_date) {
    const s = invoice.invoice_date;
    if (s.includes('.')) {
      const [d, m, y] = s.split('.');
      shortDate = y.slice(-2) + m.padStart(2,'0') + d.padStart(2,'0');
    } else {
      const dt = new Date(s);
      shortDate = String(dt.getFullYear()).slice(-2)
        + String(dt.getMonth()+1).padStart(2,'0')
        + String(dt.getDate()).padStart(2,'0');
    }
  } else {
    const now = new Date();
    shortDate = String(now.getFullYear()).slice(-2)
      + String(now.getMonth()+1).padStart(2,'0')
      + String(now.getDate()).padStart(2,'0');
  }

  const firma = (invoice.supplier_name || 'Lieferant')
    .replace(/GmbH|AG|KG|UG|mbH|Co\./gi, '')
    .trim().substring(0, 25)
    .replace(/[^a-zA-Z0-9äöüÄÖÜß -]/g, '')
    .replace(/\s+/g, '_');

  const rechnungsnr = (invoice.invoice_number || 'unbekannt')
    .replace(/[^a-zA-Z0-9-]/g, '_').substring(0, 20);

  const newFileName = `${shortDate}_${firma}_${rechnungsnr}.pdf`;

  results.push({
    json: { ...item.json, fileName: newFileName },
    binary: { data: { ...binaryData, fileName: newFileName } }
  });
}

return results;

// Lieferant lookup/create + Rechnung in Supabase eintragen
const uploadItems = $input.all();
const invoiceItems = $('Code in JavaScript7').all();

const SUPABASE_URL  = $env.SUPABASE_URL;
const SUPABASE_KEY  = $env.SUPABASE_SERVICE_ROLE_KEY;

const headers = {
  'apikey':        SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type':  'application/json',
  'Prefer':        'return=representation'
};

const normalizeDate = (s) => {
  if (!s) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  if (s.includes('.')) {
    const [d, m, y] = s.split('.');
    if (d && m && y) return `${y.trim()}-${m.trim().padStart(2,'0')}-${d.trim().padStart(2,'0')}`;
  }
  try {
    const dt = new Date(s);
    return isNaN(dt.getTime()) ? null : dt.toISOString().split('T')[0];
  } catch { return null; }
};

const results = [];

for (let i = 0; i < invoiceItems.length; i++) {
  const item    = invoiceItems[i];
  const invoice = item.json.invoice || {};
  const fileName = item.json.fileName || `invoice_${i}.pdf`;

  const pdfUrl = `${SUPABASE_URL}/storage/v1/object/public/rechnungen/${encodeURIComponent(fileName)}`;
  const supplierName = (invoice.supplier_name || '').trim() || 'Unbekannter Lieferant';

  // 1. Lieferant suchen oder anlegen
  let lieferantId = null;
  try {
    const found = await $helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/lieferanten?name=ilike.${encodeURIComponent(supplierName)}&select=id&limit=1`,
      headers
    });
    if (found.length > 0) {
      lieferantId = found[0].id;
    } else {
      const created = await $helpers.httpRequest({
        method: 'POST',
        url: `${SUPABASE_URL}/rest/v1/lieferanten`,
        headers,
        body: JSON.stringify({ name: supplierName })
      });
      lieferantId = created[0]?.id || null;
    }
  } catch (e) {
    console.error('Lieferant Fehler:', e.message);
  }

  // 2. Rechnungsnummer (Platzhalter wenn leer)
  const rechnungsnr = invoice.invoice_number ||
    `EMAIL-${new Date().getTime()}-${i}`;

  // 3. Betrag: netto bevorzugen
  const betrag = invoice.invoice_net_amount ?? invoice.invoice_amount ?? 0;
  const ustSatz = invoice.is_proforma ? 0 : (invoice.invoice_tax_rate ?? 20);

  // 4. Rechnung einfügen
  const rechnung = {
    rechnungsnr,
    rechnungsdatum: normalizeDate(invoice.invoice_date),
    faelligkeit:    normalizeDate(invoice.invoice_due_date),
    betrag,
    ust_satz:       ustSatz,
    pdf_url:        pdfUrl,
    status:         'eingegangen',
    lieferant_id:   lieferantId,
    ocr_json: {
      supplier_name:  supplierName,
      invoice_number: invoice.invoice_number,
      invoice_date:   invoice.invoice_date,
      net_amount:     invoice.invoice_net_amount,
      tax_rate:       invoice.invoice_tax_rate,
      iban:           invoice.supplier_iban
    }
  };

  try {
    const inserted = await $helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/rechnungen`,
      headers,
      body: JSON.stringify(rechnung)
    });
    results.push({
      json: {
        success:      true,
        rechnung_id:  inserted[0]?.id,
        rechnungsnr,
        supplier:     supplierName,
        betrag,
        pdf_url:      pdfUrl
      }
    });
  } catch (e) {
    results.push({
      json: { success: false, error: e.message, rechnungsnr, supplier: supplierName }
    });
  }
}

return results;
